import{_ as e,o as t,c as d,ae as s}from"./chunks/framework.DTwQaIIa.js";const m=JSON.parse('{"title":"PlaceholderAPI 占位符","description":"","frontmatter":{},"headers":[],"relativePath":"modules/gem/placeholders.md","filePath":"modules/gem/placeholders.md"}'),n={name:"modules/gem/placeholders.md"};function o(l,a,i,c,r,p){return t(),d("div",null,[...a[0]||(a[0]=[s(`<h1 id="placeholderapi-占位符" tabindex="-1">PlaceholderAPI 占位符 <a class="header-anchor" href="#placeholderapi-占位符" aria-label="Permalink to &quot;PlaceholderAPI 占位符&quot;">​</a></h1><p>EmakiGem 提供了一组 <a href="https://www.spigotmc.org/resources/placeholderapi.6245/" target="_blank" rel="noreferrer">PlaceholderAPI</a> 外部占位符，可在计分板、HUD 等任何支持 PAPI 的场景中使用。</p><div class="info custom-block"><p class="custom-block-title">前置条件</p><p>服务器需安装 PlaceholderAPI 插件。EmakiGem 会在启动时自动检测并注册，无需手动配置。</p></div><h2 id="标识符" tabindex="-1">标识符 <a class="header-anchor" href="#标识符" aria-label="Permalink to &quot;标识符&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>emakigem</span></span></code></pre></div><h2 id="主手物品宝石状态" tabindex="-1">主手物品宝石状态 <a class="header-anchor" href="#主手物品宝石状态" aria-label="Permalink to &quot;主手物品宝石状态&quot;">​</a></h2><p>所有占位符读取玩家当前主手持有物品的宝石镶嵌数据。如果主手物品没有宝石系统数据，数值类返回 <code>0</code>，字符串类返回空。</p><h3 id="总览" tabindex="-1">总览 <a class="header-anchor" href="#总览" aria-label="Permalink to &quot;总览&quot;">​</a></h3><table tabindex="0"><thead><tr><th>占位符</th><th>说明</th><th>示例返回值</th></tr></thead><tbody><tr><td><code>%emakigem_mainhand_opened_slots%</code></td><td>已开孔的槽位数量</td><td><code>3</code></td></tr><tr><td><code>%emakigem_mainhand_total_slots%</code></td><td>总槽位数量（由装备模板定义）</td><td><code>5</code></td></tr><tr><td><code>%emakigem_mainhand_filled_slots%</code></td><td>已镶嵌宝石的槽位数量</td><td><code>2</code></td></tr></tbody></table><h3 id="单槽位查询" tabindex="-1">单槽位查询 <a class="header-anchor" href="#单槽位查询" aria-label="Permalink to &quot;单槽位查询&quot;">​</a></h3><p>槽位索引从 <code>0</code> 开始。</p><table tabindex="0"><thead><tr><th>占位符</th><th>说明</th><th>示例返回值</th></tr></thead><tbody><tr><td><code>%emakigem_mainhand_slot_&lt;n&gt;_gem%</code></td><td>第 n 个槽位镶嵌的宝石 ID</td><td><code>ruby_attack</code></td></tr><tr><td><code>%emakigem_mainhand_slot_&lt;n&gt;_level%</code></td><td>第 n 个槽位宝石的等级</td><td><code>3</code></td></tr><tr><td><code>%emakigem_mainhand_slot_&lt;n&gt;_opened%</code></td><td>第 n 个槽位是否已开孔</td><td><code>true</code> / <code>false</code></td></tr></tbody></table><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%emakigem_mainhand_opened_slots%        → 3</span></span>
<span class="line"><span>%emakigem_mainhand_total_slots%         → 5</span></span>
<span class="line"><span>%emakigem_mainhand_filled_slots%        → 2</span></span>
<span class="line"><span>%emakigem_mainhand_slot_0_gem%          → ruby_attack</span></span>
<span class="line"><span>%emakigem_mainhand_slot_0_level%        → 3</span></span>
<span class="line"><span>%emakigem_mainhand_slot_0_opened%       → true</span></span>
<span class="line"><span>%emakigem_mainhand_slot_2_gem%          →</span></span>
<span class="line"><span>%emakigem_mainhand_slot_2_opened%       → true</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">使用场景</p><p>这些占位符适合在装备信息面板中展示宝石镶嵌状态，或在 HUD 中显示当前武器的宝石配置。</p></div>`,15)])])}const _=e(n,[["render",o]]);export{m as __pageData,_ as default};
